"use strict";(self.webpackChunkwoodpecker=self.webpackChunkwoodpecker||[]).push([["1943"],{7305(e){e.exports=JSON.parse('{"name":"AgentScan","slug":"agentscan","url":"https://codeberg.org/woodpecker-plugins/agentscan","icon":"https://codeberg.org/woodpecker-plugins/agentscan/raw/branch/main/agentscan.svg","description":"Plugin to check PR opener against AgentScan","docs":"<h1>AgentScan Plugin</h1>\\n<p>This plugin checks pull requests authors against <a href=\\"https://agentscan.netlify.app/\\">AgentScan</a> and posts a comment if the opener is flagged as agent.\\nSupports GitHub only as AgentScan only supports GitHub.\\nThe below pipeline configuration demonstrates simple usage:</p>\\n<pre><code class=\\"language-yml\\">steps:\\n  agentscan:\\n    image: docker.io/woodpeckerci/plugin-agentscan\\n    settings:\\n      github_token:\\n        from_secret: github_token\\n      allowlist:\\n        - my-bot\\n        - user-abc\\n</code></pre>\\n<h2>Settings Reference</h2>\\n<table>\\n<thead>\\n<tr>\\n<th>Setting</th>\\n<th>Description</th>\\n</tr>\\n</thead>\\n<tbody><tr>\\n<td><code>github_token</code></td>\\n<td>token for GitHub API</td>\\n</tr>\\n<tr>\\n<td><code>allowlist</code></td>\\n<td>users that should not be checked</td>\\n</tr>\\n</tbody></table>\\n","tags":["ai","agentscan","agent"],"author":"Woodpecker Authors","containerImage":"woodpeckerci/plugin-agentscan","containerImageUrl":"https://hub.docker.com/r/woodpeckerci/plugin-agentscan","verified":true,"iconDataUrl":"data:image/svg+xml;base64,"}')}}]);